{"db_name": "stocktrade_database", "query": "SELECT Symbol, MAX("Adj Close") as max_price FROM (
  SELECT 'SSO' as Symbol, "Adj Close" FROM "SSO" WHERE "Date" >= '2015-01-01' AND "Date" <= '2015-12-31'
  UNION ALL
  SELECT 'QLD' as Symbol, "Adj Close" FROM "QLD" WHERE "Date" >= '2015-01-01' AND "Date" <= '2015-12-31'
) GROUP BY Symbol ORDER BY max_price DESC"}

